
import forge from 'node-forge';

/**
 * RSA 公钥加密
 *
 * RSA-OAEP + SHA-256
 */
export const rsaEncrypt = async (plainText: string, publicKey: string): Promise<string> => {
  const rsaPublicKey = forge.pki.publicKeyFromPem(formatPublicKey(publicKey));

  const encryptedData = rsaPublicKey.encrypt(forge.util.encodeUtf8(plainText), 'RSA-OAEP', {
    md: forge.md.sha256.create(),
  });

  return forge.util.encode64(encryptedData);
};

/**
 * Base64 公钥转 PEM
 */
const formatPublicKey = (publicKey: string): string => {
  const formattedPublicKey = publicKey.match(/.{1,64}/g)?.join('\n') ?? publicKey;

  return `-----BEGIN PUBLIC KEY-----
${formattedPublicKey}
-----END PUBLIC KEY-----`;
};